interface GameSelectorGridProps {
  counts?: Record<string, number>
}

export function GameSelectorGrid({ counts }: GameSelectorGridProps) {
  return (
    <section className="px-5 py-10 sm:px-12 lg:py-16">
      <div className="mx-auto max-w-[1344px]">
        <p className="mb-7 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow">
          Shop by Game
        </p>
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4 sm:gap-4">
          {GAMES.map((game) => (
            <GameTile
              key={game.code}
              code={game.code}
              display={game.display}
              image={game.image}
