              overlayGradient={game.overlayGradient}
              count={counts?.[game.code]}
            />
          ))}
        </div>
      </div>
    </section>
  )
}

import { render, screen } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import React from 'react'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/lib/algolia', () => ({
  algoliaClient: {},
  CARDS_INDEX: 'test_cards',
}))

vi.mock('@/components/search/AlgoliaSearchResults', () => ({
  AlgoliaSearchResults: (props: { initialQuery: string; initialGame?: string }) => (
    <div data-testid="algolia-results" data-query={props.initialQuery} data-game={props.initialGame ?? ""} />
  ),
}))

vi.mock('../SearchAnalytics', () => ({
  SearchAnalytics: () => <div data-testid="search-analytics">SearchAnalytics</div>,
}))

vi.mock('@/components/decks/MyDecksWidget', () => ({
  MyDecksWidget: () => <div data-testid="my-decks">MyDecksWidget</div>,
}))

// ─── Component under test ─────────────────────────────────────────────────────

import { CardBrowsingPage } from '../CardBrowsingPage'

describe('CardBrowsingPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('renders AlgoliaSearchResults', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('algolia-results')).toBeInTheDocument()
    expect(screen.queryByTestId('old-card-filters')).not.toBeInTheDocument()
  })

  it('passes initialQuery to AlgoliaSearchResults', () => {
    render(<CardBrowsingPage initialQuery="charizard" />)
    const el = screen.getByTestId('algolia-results')
    expect(el).toHaveAttribute('data-query', 'charizard')
  })

  it('passes empty string to AlgoliaSearchResults when no initialQuery provided', () => {
    render(<CardBrowsingPage />)
    const el = screen.getByTestId('algolia-results')
    expect(el).toHaveAttribute('data-query', '')
  })

  it('renders SearchAnalytics in the right sidebar', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('search-analytics')).toBeInTheDocument()
  })

  it('renders MyDecksWidget in the right sidebar', () => {
    render(<CardBrowsingPage />)
    expect(screen.getByTestId('my-decks')).toBeInTheDocument()
  })

  it('passes initialGame to AlgoliaSearchResults', () => {
    render(<CardBrowsingPage initialQuery="charizard" initialGame="POKEMON" />)
    expect(screen.getByTestId('algolia-results')).toHaveAttribute('data-game', 'POKEMON')
  })

  it('omits initialGame from AlgoliaSearchResults when not provided', () => {
    render(<CardBrowsingPage initialQuery="charizard" />)
    expect(screen.getByTestId('algolia-results')).toHaveAttribute('data-game', '')
  })

  it('uses design token classes in CardBrowsingPage (no hardcoded gray/blue)', () => {
    const { container } = render(<CardBrowsingPage />)
    const html = container.innerHTML
    expect(html).not.toContain('bg-gray-100')
    expect(html).not.toContain('text-gray-700')
    expect(html).not.toContain('bg-blue-600')
    expect(html).not.toContain('bg-blue-100')
  })
})

"use client"

import { useState } from "react"
import { FacetGroup } from "./FacetGroup"
import { PricePresets } from "./PricePresets"
import { SortControl } from "./SortControl"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet"

// ─── Game color dots ───────────────────────────────────────────────────────────

const GAME_DOTS: Record<string, string> = {
  MTG:     "var(--game-mtg)",
  POKEMON: "var(--game-pokemon)",
  YUGIOH:  "var(--game-yugioh)",
  OPTCG:   "var(--game-optcg)",
}

const GAME_NAMES: Record<string, string> = {
  MTG: "MTG", POKEMON: "Pokémon", YUGIOH: "Yu-Gi-Oh!", OPTCG: "One Piece",
}

export function GameLabel({ value }: { value: string }) {
  const color = GAME_DOTS[value]
  return (
    <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
      {color && (
        <span
          data-game-dot={value}
          style={{ width: 8, height: 8, borderRadius: "50%", background: color, flexShrink: 0, display: "inline-block" }}
        />
      )}
      {GAME_NAMES[value] ?? value}
    </span>
  )
}

// ─── Condition color badges ────────────────────────────────────────────────────

const CONDITION_BADGES: Record<string, { color: string; bg: string }> = {
  NM:  { color: "var(--positive)",  bg: "color-mix(in srgb, var(--positive) 15%, transparent)" },
  LP:  { color: "color-mix(in srgb, var(--positive) 70%, transparent)", bg: "color-mix(in srgb, var(--positive) 8%, transparent)" },
  MP:  { color: "var(--warning)",   bg: "color-mix(in srgb, var(--warning) 12%, transparent)" },
  HP:  { color: "var(--negative)",  bg: "color-mix(in srgb, var(--negative) 12%, transparent)" },
  DMG: { color: "color-mix(in srgb, var(--negative) 60%, transparent)", bg: "color-mix(in srgb, var(--negative) 8%, transparent)" },
}

const CONDITION_NAMES: Record<string, string> = {
  NM: "Near Mint", LP: "Lightly Played", MP: "Moderately Played",
  HP: "Heavily Played", DMG: "Damaged",
}

export function ConditionLabel({ value }: { value: string }) {
  const badge = CONDITION_BADGES[value]
  return (
    <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
      {badge && (
        <span style={{
          fontSize: 10, fontWeight: 700, padding: "1px 5px", borderRadius: 4,
          background: badge.bg, color: badge.color,
        }}>
          {value}
        </span>
      )}
      {CONDITION_NAMES[value] ?? value}
    </span>
  )
}

// ─── Filter panel ──────────────────────────────────────────────────────────────

interface SearchFiltersProps {
  activeFilterCount: number
}

export function FilterPanelContents() {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
      <FacetGroup attribute="game"      title="Game"      defaultOpen renderLabel={(v) => <GameLabel value={v} />} />
      <FacetGroup attribute="set_name"  title="Set" />
      <FacetGroup attribute="rarity"    title="Rarity" />
      <FacetGroup attribute="condition" title="Condition"  defaultOpen renderLabel={(v) => <ConditionLabel value={v} />} />
      <div style={{ padding: "8px 16px 4px", fontSize: 11, color: "var(--text-tertiary, #7B72A8)", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em" }}>
        Price Range
      </div>
      <PricePresets attribute="lowest_price" />
      <FacetGroup attribute="language"  title="Language" />
    </div>
  )
}

export function SearchFilters({ activeFilterCount }: SearchFiltersProps) {
  const [open, setOpen] = useState(false)

  return (
    <>
      {/* Desktop sidebar */}
      <aside className="hidden md:block w-[280px] flex-shrink-0 rounded-2xl border border-border overflow-hidden sticky top-[110px]" style={{ background: "var(--bg-surface-1, #18162A)" }}>
        <div style={{ padding: "14px 20px", borderBottom: "1px solid var(--border)", display: "flex", alignItems: "center" }}>
          <span className="font-barlow" style={{ fontSize: 13, fontWeight: 600, color: "var(--text-primary, #F0EEFF)" }}>Filters</span>
        </div>
        <FilterPanelContents />
      </aside>

      {/* Mobile toolbar: Filters + Sort buttons */}
      <div className="flex md:hidden items-center gap-2">
        <Sheet open={open} onOpenChange={setOpen}>
          <SheetTrigger asChild>
            <button
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                fontSize: 13,
                padding: "6px 14px",
                borderRadius: 8,
                border: "1.5px solid var(--border)",
                background: "var(--bg-surface-2, #21203A)",
                color: "var(--text-primary, #F0EEFF)",
                cursor: "pointer",
              }}
            >
              Filters
              {activeFilterCount > 0 && (
                <span
                  data-testid="filter-count-badge"
                  style={{
                    fontSize: 11,
                    background: "var(--interactive, #8B5CF6)",
                    color: "var(--primary-foreground)",
                    borderRadius: 999,
                    padding: "1px 7px",
                    fontWeight: 600,
                  }}
                >
                  {activeFilterCount}
                </span>
              )}
            </button>
          </SheetTrigger>

          <SheetContent
            side="bottom"
            aria-label="Search Filters"
            style={{ maxHeight: "85dvh", overflowY: "auto", padding: 0 }}
          >
            <SheetHeader style={{ padding: "16px 16px 0" }}>
              <SheetTitle>Filters</SheetTitle>
              <SheetDescription className="sr-only">
                Filter search results by game, condition, price range, set, and rarity.
              </SheetDescription>
            </SheetHeader>
            <FilterPanelContents />
            <div style={{ padding: "12px 16px 24px", display: "flex", gap: 8 }}>
              <button
                onClick={() => setOpen(false)}
                style={{
                  flex: 1,
                  padding: "10px",
                  borderRadius: 8,
                  border: "none",
                  background: "var(--interactive, #8B5CF6)",
                  color: "var(--primary-foreground)",
                  fontSize: 14,
                  fontWeight: 600,
                  cursor: "pointer",
                }}
              >
                Apply Filters
              </button>
            </div>
          </SheetContent>
        </Sheet>
        <SortControl />
      </div>
    </>
  )
}

"use client"

import { useCurrentRefinements } from "react-instantsearch"

const CONDITION_LABELS: Record<string, string> = {
  NM:  "Near Mint",
  LP:  "Lightly Played",
  MP:  "Moderately Played",
  HP:  "Heavily Played",
  DMG: "Damaged",
}

function resolveLabel(label: string): string {
  return CONDITION_LABELS[label] ?? label
}

export function ActiveFilterChips() {
  const { items } = useCurrentRefinements()

  const clearAll = () => {
    setTimeout(() => {
      for (const item of items) {
        for (const refinement of item.refinements) {
          item.refine(refinement)
        }
      }
    }, 0)
  }

  const rowStyle: React.CSSProperties = {
    display: "flex",
    alignItems: "center",
    gap: 8,
    padding: "10px 20px",
    background: "var(--bg-surface-1, #18162A)",
    borderBottom: "1px solid var(--border)",
    minHeight: 44,
    overflowX: "auto",
    scrollbarWidth: "none",
  }

  if (items.length === 0) {
    return (
      <div style={rowStyle}>
        <span style={{ fontSize: 12, color: "var(--text-tertiary, #7B72A8)", fontStyle: "italic" }}>
          No filters active — showing all results
        </span>
      </div>
    )
  }

  return (
    <div style={rowStyle}>
      <ul
        role="list"
        style={{
          display: "flex",
          alignItems: "center",
          gap: 6,
          listStyle: "none",
          margin: 0,
          padding: 0,
          flexShrink: 0,
          flexWrap: "wrap",
        }}
      >
        {items.flatMap((item) =>
          item.refinements.map((refinement) => {
            const displayLabel = resolveLabel(refinement.label)
            return (
              <li key={`${item.attribute}:${refinement.value}`}>
                <span
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    gap: 4,
                    fontSize: 12,
                    fontWeight: 500,
                    padding: "4px 10px",
                    borderRadius: 999,
                    background: "var(--interactive-subtle)",
                    border: "1px solid var(--border-active)",
                    color: "var(--interactive, #8B5CF6)",
                    whiteSpace: "nowrap",
                  }}
                >
                  {displayLabel}
                  <button
                    aria-label={`Remove ${displayLabel} filter`}
                    onClick={() => setTimeout(() => item.refine(refinement), 0)}
                    className="opacity-70 hover:opacity-100 transition-opacity"
                    style={{
                      background: "transparent",
                      border: "none",
                      cursor: "pointer",
                      color: "var(--interactive, #8B5CF6)",
                      fontSize: 14,
                      lineHeight: 1,
                      padding: 0,
                      marginLeft: 2,
                    }}
                  >
                    ×
                  </button>
                </span>
              </li>
            )
          })
        )}
      </ul>

      <button
        onClick={clearAll}
        style={{
          marginLeft: "auto",
          flexShrink: 0,
          fontSize: 12,
          fontWeight: 500,
          padding: "4px 12px",
          borderRadius: 999,
          border: "1px solid color-mix(in srgb, var(--negative) 30%, transparent)",
          color: "var(--negative, #EF5350)",
          background: "transparent",
          cursor: "pointer",
          whiteSpace: "nowrap",
        }}
      >
        Clear All
      </button>
    </div>
  )
}

"use client"

import { useSortBy } from "react-instantsearch"
import { CARDS_INDEX, CARDS_INDEX_PRICE_ASC, CARDS_INDEX_PRICE_DESC } from "@/lib/algolia"

const SORT_ITEMS = [
  { label: "Relevance",          value: CARDS_INDEX },
  { label: "Price: Low to High", value: CARDS_INDEX_PRICE_ASC },
  { label: "Price: High to Low", value: CARDS_INDEX_PRICE_DESC },
]

const SELECT_ID = "sort-control"

export function SortControl() {
  const { currentRefinement, refine } = useSortBy({ items: SORT_ITEMS })
  const isAsc  = currentRefinement === CARDS_INDEX_PRICE_ASC
  const isDesc = currentRefinement === CARDS_INDEX_PRICE_DESC
  const isActive = isAsc || isDesc

  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <label
        htmlFor={SELECT_ID}
        style={{ fontSize: 12, color: "var(--text-tertiary, #7B72A8)", whiteSpace: "nowrap" }}
      >
        Sort:
      </label>

      {isActive && (
        <span
          data-testid="sort-active-chip"
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 4,
            fontSize: 12,
            fontWeight: 500,
            padding: "4px 10px",
            borderRadius: 999,
            background: "var(--bg-surface-2, #21203A)",
            border: "1px solid var(--border)",
            color: "var(--text-primary, #F0EEFF)",
          }}
        >
          <span style={{ color: "var(--accent-primary, #8B5CF6)", fontWeight: 700 }}>
            {isAsc ? "↑" : "↓"}
          </span>
          {isAsc ? "Price: Low to High" : "Price: High to Low"}
        </span>
      )}

      <select
        id={SELECT_ID}
        value={currentRefinement}
        onChange={(e) => { const v = e.target.value; setTimeout(() => refine(v), 0) }}
        style={{
          fontSize: 12,
          background: "var(--bg-surface-2, #21203A)",
          color: "var(--text-primary, #F0EEFF)",
          border: "1.5px solid var(--border)",
          borderRadius: 6,
          padding: "5px 8px",
          cursor: "pointer",
        }}
      >
        {SORT_ITEMS.map((item) => (
          <option key={item.value} value={item.value}>
            {item.label}
          </option>
        ))}
      </select>
    </div>
  )
}

import { liteClient, LiteClient } from 'algoliasearch/lite'

let _client: LiteClient | null = null

function createClient(): LiteClient {
  if (!_client) {
    const appId = process.env.NEXT_PUBLIC_ALGOLIA_ID
    const searchKey = process.env.NEXT_PUBLIC_ALGOLIA_SEARCH_KEY

    if (!appId || !searchKey) {
      throw new Error(
        'Algolia is not configured: set NEXT_PUBLIC_ALGOLIA_ID and NEXT_PUBLIC_ALGOLIA_SEARCH_KEY'
      )
    }

    _client = liteClient(appId, searchKey)
  }
  return _client
}

// Lazy proxy — the actual client is created on first property access.
// This prevents initialization errors when env vars are not set at module load time
// (e.g. during SSR or build when NEXT_PUBLIC_* vars are absent).
export const algoliaClient = new Proxy({} as LiteClient, {
  get(_target, prop) {
    return (createClient() as any)[prop]
  },
})

export const CARDS_INDEX = process.env.NEXT_PUBLIC_ALGOLIA_INDEX_CARDS ?? 'cards_catalog'

export const CARDS_INDEX = process.env.NEXT_PUBLIC_ALGOLIA_INDEX_CARDS ?? 'cards_catalog'
export const CARDS_INDEX_PRICE_ASC =
  process.env.NEXT_PUBLIC_ALGOLIA_INDEX_CARDS_PRICE_ASC ?? `${CARDS_INDEX}_price_asc`
export const CARDS_INDEX_PRICE_DESC =
  process.env.NEXT_PUBLIC_ALGOLIA_INDEX_CARDS_PRICE_DESC ?? `${CARDS_INDEX}_price_desc`

import { Metadata } from "next"
import { cookies } from "next/headers"
import { getBaseURL } from "@/lib/server-utils"
import { CardBrowsingPage } from "@/components/cards/CardBrowsingPage"

export async function generateMetadata(): Promise<Metadata> {
  const baseUrl = await getBaseURL()

  return {
    title: "Browse Cards | SideDecked",
    description: "Discover and shop trading cards from Magic: The Gathering, Pokémon, Yu-Gi-Oh!, and One Piece TCG.",
    openGraph: {
      title: "Browse Trading Cards | SideDecked",
      description: "Discover cards from your favorite TCG games with advanced search and filtering.",
      url: `${baseUrl}/cards`,
      type: "website",
    },
  }
}

const VALID_GAME_CODES = new Set(["MTG", "POKEMON", "YUGIOH", "OPTCG"])

type Props = {
  searchParams: Promise<{ q?: string; game?: string }>
}

export default async function CardsPage({ searchParams }: Props) {
  const { q: query, game: gameParam } = await searchParams
  const cookieJar = await cookies()
  const rawGame = gameParam ?? cookieJar.get("sd_game_pref")?.value
  const gameCode =
    rawGame !== undefined && VALID_GAME_CODES.has(rawGame.toUpperCase())
      ? rawGame.toUpperCase()
      : undefined

  return (
    <CardBrowsingPage initialQuery={query} initialGame={gameCode} />
  )
}

"use client"

import Link from "next/link"

interface GameTileProps {
  code: string
  display: string
  image: string
  bgGradient: string
  overlayGradient: string
  count?: number
}

export function GameTile({
  code,
  display,
  image,
  bgGradient,
  overlayGradient,
  count,
}: GameTileProps) {
  function handleClick() {
    try {
      const secure = location.protocol === "https:" ? "; Secure" : ""
      document.cookie = `sd_game_pref=${encodeURIComponent(code)}; max-age=2592000; path=/; SameSite=Lax${secure}`
    } catch {
      // Best-effort — navigation fires regardless
    }
  }

  const ariaLabel =
    count !== undefined ? `${display} — ${count.toLocaleString()} cards` : display

  return (
    <Link
      href={`/cards?game=${encodeURIComponent(code)}`}
      aria-label={ariaLabel}
      onClick={handleClick}
      className="group relative block cursor-pointer overflow-hidden rounded-2xl transition-all duration-200 [@media(pointer:fine)]:hover:scale-[1.02] [@media(pointer:fine)]:hover:shadow-[0_8px_40px_rgba(0,0,0,0.4)] active:scale-[0.98] focus-visible:outline-2 focus-visible:outline-accent focus-visible:outline-offset-2"
      style={{ aspectRatio: "16 / 10" }}
    >
      {/* Gradient background */}
      <div
        className="absolute inset-0"
        style={{ background: bgGradient }}
      >
        {/* Pattern decoration */}
        <div
          className="absolute inset-0"
          style={{
            backgroundImage:
              "radial-gradient(circle at 30% 30%, rgba(255,255,255,0.03) 0%, transparent 60%), radial-gradient(circle at 70% 60%, rgba(255,255,255,0.02) 0%, transparent 50%)",
          }}
        />
      </div>

      {/* Card-back image background */}
      <div
        className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-40"
        style={{ backgroundImage: `url(${image})` }}
      />

      {/* Game-colour overlay */}
      <div
        className="absolute inset-0 flex flex-col justify-end p-4 sm:p-6"
        style={{ background: overlayGradient }}
      >
        <span className="font-barlow-condensed text-base font-bold text-white sm:text-[22px]">
          {display}
        </span>
        {count !== undefined && (
          <span
            data-testid="tile-count"
            className="font-dm-mono text-[11px] text-white/70 sm:text-xs"
          >
            {count.toLocaleString()} cards
          </span>
        )}
      </div>
    </Link>
  )
}

