"use client"

import { useRefinementList } from "react-instantsearch"

// ─── Game data ─────────────────────────────────────────────────────────────────

export const GAME_STRIP_ITEMS = [
  {
    code: null as string | null,
    display: "All Games",
    shortName: "All",
    bgGradient: "linear-gradient(135deg, #1a103a 0%, #2a1a4a 50%, #1a2030 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(139,92,246,0.08) 0%, rgba(139,92,246,0.45) 100%)",
    activeClass: "all" as const,
    borderColor: "var(--brand-primary, #8B5CF6)",
    glowColor: "rgba(139, 92, 246, 0.25)",
    dotColor: "var(--brand-primary, #8B5CF6)",
  },
  {
    code: "MTG",
    display: "Magic: The Gathering",
    shortName: "MTG",
    bgGradient: "linear-gradient(135deg, #1a103a 0%, #2d1b69 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(167,139,250,0.08) 0%, rgba(167,139,250,0.50) 100%)",
    activeClass: "mtg" as const,
    borderColor: "var(--game-mtg, #A78BFA)",
    glowColor: "rgba(167, 139, 250, 0.25)",
    dotColor: "var(--game-mtg, #A78BFA)",
  },
  {
    code: "POKEMON",
    display: "Pokémon",
    shortName: "PKMN",
    bgGradient: "linear-gradient(135deg, #1a1a08 0%, #3d3000 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(252,211,77,0.06) 0%, rgba(252,211,77,0.45) 100%)",
    activeClass: "poke" as const,
    borderColor: "var(--game-pokemon, #FCD34D)",
    glowColor: "rgba(252, 211, 77, 0.25)",
    dotColor: "var(--game-pokemon, #FCD34D)",
  },
  {
    code: "YUGIOH",
    display: "Yu-Gi-Oh!",
    shortName: "YGO",
    bgGradient: "linear-gradient(135deg, #081a30 0%, #0d2b5e 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(96,165,250,0.08) 0%, rgba(96,165,250,0.50) 100%)",
    activeClass: "ygo" as const,
    borderColor: "var(--game-ygo, #60A5FA)",
    glowColor: "rgba(96, 165, 250, 0.25)",
    dotColor: "var(--game-ygo, #60A5FA)",
  },
  {
    code: "OPTCG",
    display: "One Piece",
    shortName: "OP",
    bgGradient: "linear-gradient(135deg, #081a14 0%, #0d3d2b 100%)",
    overlayGradient: "linear-gradient(180deg, rgba(52,211,153,0.06) 0%, rgba(52,211,153,0.45) 100%)",
    activeClass: "op" as const,
    borderColor: "var(--game-op, #34D399)",
    glowColor: "rgba(52, 211, 153, 0.25)",
    dotColor: "var(--game-op, #34D399)",
  },
] as const

// ─── Cookie helper ─────────────────────────────────────────────────────────────

function setGameCookie(code: string | null) {
  try {
    const secure = location.protocol === "https:" ? "; Secure" : ""
    if (code === null) {
      // Clear cookie for "All Games"
      document.cookie = `sd_game_pref=; max-age=0; path=/; SameSite=Lax${secure}`
    } else {
      document.cookie = `sd_game_pref=${encodeURIComponent(code)}; max-age=2592000; path=/; SameSite=Lax${secure}`
    }
  } catch {
    // Best-effort
  }
}

// ─── Component ─────────────────────────────────────────────────────────────────

export function GameSelectorStrip() {
  const { items, refine } = useRefinementList({ attribute: "game" })

  // Determine which game is currently selected via the Algolia refinement
  const activeRefinements = items.filter((i) => i.isRefined).map((i) => i.value)
  // Single game selected means that game is active; no selection = "All Games"
  const activeGameCode = activeRefinements.length === 1 ? activeRefinements[0] : null

  function handleSelect(code: string | null) {
    // Clear any existing game refinements first
    for (const item of items) {
      if (item.isRefined) {
        refine(item.value)
      }
    }
    // Then set the new one (if not "All Games")
    if (code !== null) {
      // Need to wait for clears to process, then apply new refinement
      // Since refine is synchronous in its state update, we can call it right after
      refine(code)
    }
    setGameCookie(code)
  }

  return (
    <div style={{ padding: "24px 32px 0" }}>
      {/* Desktop: 5-column grid */}
      <div
        className="hidden md:grid"
        data-testid="game-strip-desktop"
        style={{
          gridTemplateColumns: "repeat(5, 1fr)",
          gap: 12,
        }}
      >
        {GAME_STRIP_ITEMS.map((game) => {
          const isActive = game.code === activeGameCode
          return (
            <button
              key={game.code ?? "all"}
              data-testid={`game-strip-${game.code ?? "all"}`}
              onClick={() => handleSelect(game.code)}
              aria-pressed={isActive}
              aria-label={game.display}
              style={{
                position: "relative",
                borderRadius: 12,
                overflow: "hidden",
                aspectRatio: "16 / 7",
                cursor: "pointer",
                transition: "transform 0.2s, box-shadow 0.2s",
                border: isActive
                  ? `2px solid ${game.borderColor}`
                  : "2px solid transparent",
                boxShadow: isActive
                  ? `0 0 20px ${game.glowColor}`
                  : "none",
                background: "transparent",
                padding: 0,
                textAlign: "left",
              }}
            >
              {/* Background gradient */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  background: game.bgGradient,
                }}
              >
                <div
                  style={{
                    position: "absolute",
                    inset: 0,
                    backgroundImage:
                      "radial-gradient(circle at 30% 30%, rgba(255,255,255,0.03) 0%, transparent 60%), radial-gradient(circle at 70% 60%, rgba(255,255,255,0.02) 0%, transparent 50%)",
                  }}
                />
              </div>
              {/* Overlay with name + count */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "flex-end",
                  padding: "14px 16px",
                  background: game.overlayGradient,
                }}
              >
                <span
                  style={{
                    fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
                    fontWeight: 700,
                    fontSize: 17,
                    color: "white",
                    marginBottom: 2,
                  }}
                >
                  {game.display}
                </span>
                <span
                  style={{
                    fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                    fontSize: 11,
                    color: "rgba(255, 255, 255, 0.7)",
                  }}
                >
                  {/* Count from Algolia facets */}
                  {game.code === null
                    ? `${items.reduce((sum, i) => sum + i.count, 0).toLocaleString()} cards`
                    : `${items.find((i) => i.value === game.code)?.count?.toLocaleString() ?? "0"} cards`}
                </span>
              </div>
            </button>
          )
        })}
      </div>

      {/* Mobile: horizontal pill scroll */}
      <div
        className="flex md:hidden gap-2 overflow-x-auto pb-1"
        data-testid="game-strip-mobile"
        style={{ scrollbarWidth: "none" }}
      >
        {GAME_STRIP_ITEMS.map((game) => {
          const isActive = game.code === activeGameCode
          return (
            <button
              key={game.code ?? "all"}
              data-testid={`game-pill-${game.code ?? "all"}`}
              onClick={() => handleSelect(game.code)}
              aria-pressed={isActive}
              style={{
                flexShrink: 0,
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "6px 14px",
                borderRadius: 999,
                border: isActive
                  ? `1px solid var(--brand-primary, #8B5CF6)`
                  : "1px solid var(--border-default, #2C2A4A)",
                background: isActive
                  ? "rgba(139, 92, 246, 0.12)"
                  : "var(--bg-surface-2, #21203A)",
                fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                fontSize: 12,
                fontWeight: 600,
                color: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-secondary, #B8B0D8)",
                cursor: "pointer",
                whiteSpace: "nowrap",
              }}
            >
              <span
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  background: game.dotColor,
                  flexShrink: 0,
                }}
              />
              {game.shortName}
            </button>
          )
        })}
      </div>
    </div>
  )
}

"use client"

import { useState } from "react"
import { useNumericMenu, useRefinementList } from "react-instantsearch"

// ─── Category definitions ──────────────────────────────────────────────────────

interface Category {
  label: string
  /** Type of Algolia refinement this pill triggers */
  type: "none" | "numeric" | "facet"
  /** For numeric: the encoded range string for Algolia numericMenu */
  numericValue?: string
  /** For facet: attribute + value */
  facetAttribute?: string
  facetValue?: string
}

const CATEGORIES: Category[] = [
  { label: "All", type: "none" },
  { label: "New Releases", type: "facet", facetAttribute: "is_new_release", facetValue: "true" },
  { label: "Trending", type: "facet", facetAttribute: "is_trending", facetValue: "true" },
  { label: "Under $5", type: "numeric", numericValue: ":%7B%7D:5" },
  { label: "Staples", type: "facet", facetAttribute: "is_staple", facetValue: "true" },
  { label: "Format Legal", type: "facet", facetAttribute: "is_format_legal", facetValue: "true" },
  { label: "Foils & Special", type: "facet", facetAttribute: "is_foil", facetValue: "true" },
]

// ─── Component ─────────────────────────────────────────────────────────────────

export function CategoryPills() {
