                fontWeight: 600,
                padding: "6px 18px",
                borderRadius: 999,
                border: isActive
                  ? "1px solid var(--brand-primary, #8B5CF6)"
                  : "1px solid var(--border-default, #2C2A4A)",
                background: isActive
                  ? "rgba(139, 92, 246, 0.12)"
                  : "transparent",
                color: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-secondary, #B8B0D8)",
                cursor: "pointer",
                transition: "all 0.15s",
                whiteSpace: "nowrap",
              }}
            >
              {cat.label}
            </button>
          )
        })}
      </div>
    </div>
  )
}

"use client"

// ─── Popular sets data per game (MVP: hardcoded) ───────────────────────────────

